/**
 * Audit logging service — records every notification dispatched through the system.
 *
 * Listens for 'notification:requested' events on the EventBus and logs each one
 * with a timestamp, channel, recipient, and subject. Provides query methods for
 * retrieving audit entries by channel or recipient.
 *
 * Depends on:
 * - EventBus (event system) for receiving notification events
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationRequestedEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface AuditEntry {
  id: string;
  channel: string;
  recipient: string;
  subject: string;
  body: string;
  timestamp: Date;
}

let nextAuditId = 1;

function generateAuditId(): string {
  return `audit-${String(nextAuditId++).padStart(4, '0')}`;
}

export function resetAuditIdCounter(): void {
  nextAuditId = 1;
}

export class AuditService {
  private logger = new Logger('AuditService');
  private entries: AuditEntry[] = [];

  constructor(private eventBus: EventBus) {
    this.eventBus.on<NotificationRequestedEvent>(
      'notification:requested',
      (event) => this.recordEntry(event),
    );
  }

  private recordEntry(event: NotificationRequestedEvent): void {
    const entry: AuditEntry = {
      id: generateAuditId(),
      channel: event.channel,
      recipient: event.recipient,
      subject: event.subject,
      body: event.body,
      timestamp: event.timestamp,
    };

    this.entries.push(entry);
    this.logger.info(
      `Audit entry recorded: ${entry.id} — ${entry.channel} to ${entry.recipient} [${entry.subject}]`,
    );
  }

  getEntries(): AuditEntry[] {
    return [...this.entries];
  }

  getEntriesByChannel(channel: string): AuditEntry[] {
    return this.entries.filter((e) => e.channel === channel);
  }

  getEntriesByRecipient(recipient: string): AuditEntry[] {
    return this.entries.filter((e) => e.recipient === recipient);
  }

  getEntryCount(): number {
    return this.entries.length;
  }

  clearEntries(): void {
    this.entries = [];
  }
}

/**
 * Notification preferences service — allows per-user channel overrides.
 *
 * Users can set a preferred channel for a given notification priority. When a
 * preference exists, it overrides the default priority-based routing. If no
 * preference is set, the PriorityRouter default is used.
 *
 * Example: A user may prefer to receive all 'low' priority notifications via
 * 'email' instead of the default 'webhook'.
 */

import type { NotificationPriority } from './priority-router.js';

export type ChannelPreference = 'email' | 'sms' | 'webhook';

export interface UserPreferences {
  userId: string;
  channelOverrides: Partial<Record<NotificationPriority, ChannelPreference>>;
}

export class NotificationPreferencesService {
  private preferences: Map<string, UserPreferences> = new Map();

  /**
   * Set a channel override for a user at a given priority level.
   */
  setChannelOverride(
    userId: string,
    priority: NotificationPriority,
    channel: ChannelPreference,
  ): void {
    let prefs = this.preferences.get(userId);
    if (!prefs) {
      prefs = { userId, channelOverrides: {} };
      this.preferences.set(userId, prefs);
    }
    prefs.channelOverrides[priority] = channel;
  }

  /**
   * Remove a channel override for a user at a given priority level.
   */
  removeChannelOverride(userId: string, priority: NotificationPriority): void {
    const prefs = this.preferences.get(userId);
    if (prefs) {
      delete prefs.channelOverrides[priority];
    }
  }

  /**
   * Resolve the channel for a user and priority. Returns the user's override
   * if one exists, or undefined to fall back to the default priority routing.
   */
  resolveChannel(
    userId: string,
    priority: NotificationPriority,
  ): ChannelPreference | undefined {
    const prefs = this.preferences.get(userId);
    if (!prefs) {
      return undefined;
    }
    return prefs.channelOverrides[priority];
  }

  /**
   * Get all preferences for a user.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferences.get(userId);
  }

  /**
   * Remove all preferences for a user.
   */
  clearPreferences(userId: string): void {
    this.preferences.delete(userId);
  }

  /**
   * Remove all stored preferences (useful for testing).
   */
  clearAll(): void {
    this.preferences.clear();
  }
}

