import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  AuditService,
  resetAuditIdCounter,
} from '../../src/services/audit.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';

describe('AuditService', () => {
  let eventBus: EventBus;
  let auditService: AuditService;
  let notificationService: NotificationService;

  beforeEach(() => {
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    auditService = new AuditService(eventBus);
    resetNotificationIdCounter();
    resetAuditIdCounter();
  });

  it('should record an audit entry for each notification dispatched', async () => {
    await notificationService.notify({
      priority: 'normal',
      recipient: 'alice@example.com',
      subject: 'Hello',
      body: 'World',
    });

    const entries = auditService.getEntries();
    expect(entries).toHaveLength(1);
    expect(entries[0]?.channel).toBe('email');
    expect(entries[0]?.recipient).toBe('alice@example.com');
    expect(entries[0]?.subject).toBe('Hello');
    expect(entries[0]?.body).toBe('World');
    expect(entries[0]?.id).toBe('audit-0001');
  });

  it('should record multiple entries with sequential IDs', async () => {
    await notificationService.notify({
      priority: 'urgent',
      recipient: '+1234567890',
      subject: 'Alert',
      body: 'Down!',
    });
    await notificationService.notify({
      priority: 'low',
      recipient: 'https://hook.io/x',
      subject: 'Info',
      body: 'Done',
    });

    const entries = auditService.getEntries();
    expect(entries).toHaveLength(2);
    expect(entries[0]?.id).toBe('audit-0001');
    expect(entries[0]?.channel).toBe('sms');
    expect(entries[1]?.id).toBe('audit-0002');
    expect(entries[1]?.channel).toBe('webhook');
  });

  it('should filter entries by channel', async () => {
    await notificationService.notify({
      priority: 'urgent',
      recipient: '+1234567890',
      subject: 'A',
      body: 'A',
    });
    await notificationService.notify({
      priority: 'normal',
      recipient: 'bob@example.com',
      subject: 'B',
      body: 'B',
    });
    await notificationService.notify({
      priority: 'low',
      recipient: 'https://hook.io/x',
      subject: 'C',
      body: 'C',
    });

    expect(auditService.getEntriesByChannel('sms')).toHaveLength(1);
    expect(auditService.getEntriesByChannel('email')).toHaveLength(1);
    expect(auditService.getEntriesByChannel('webhook')).toHaveLength(1);
  });

  it('should filter entries by recipient', async () => {
    await notificationService.notify({
      priority: 'normal',
      recipient: 'alice@example.com',
      subject: 'A',
      body: 'A',
    });
    await notificationService.notify({
      priority: 'normal',
      recipient: 'bob@example.com',
      subject: 'B',
      body: 'B',
    });

    expect(auditService.getEntriesByRecipient('alice@example.com')).toHaveLength(1);
    expect(auditService.getEntriesByRecipient('bob@example.com')).toHaveLength(1);
    expect(auditService.getEntriesByRecipient('nobody@example.com')).toHaveLength(0);
  });

  it('should report correct entry count', async () => {
    expect(auditService.getEntryCount()).toBe(0);

    await notificationService.notify({
      priority: 'normal',
      recipient: 'alice@example.com',
      subject: 'X',
      body: 'X',
    });

    expect(auditService.getEntryCount()).toBe(1);
  });

  it('should clear entries', async () => {
    await notificationService.notify({
      priority: 'normal',
      recipient: 'alice@example.com',
      subject: 'X',
      body: 'X',
    });

    auditService.clearEntries();
    expect(auditService.getEntries()).toHaveLength(0);
    expect(auditService.getEntryCount()).toBe(0);
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { NotificationPreferencesService } from '../../src/services/notification-preferences.service.js';

describe('NotificationPreferencesService', () => {
  let service: NotificationPreferencesService;

  beforeEach(() => {
    service = new NotificationPreferencesService();
  });

  it('should return undefined when no preference is set', () => {
    expect(service.resolveChannel('user-1', 'normal')).toBeUndefined();
  });

  it('should store and retrieve a channel override', () => {
    service.setChannelOverride('user-1', 'normal', 'sms');
    expect(service.resolveChannel('user-1', 'normal')).toBe('sms');
  });

  it('should not affect other priorities for the same user', () => {
    service.setChannelOverride('user-1', 'normal', 'sms');
    expect(service.resolveChannel('user-1', 'urgent')).toBeUndefined();
    expect(service.resolveChannel('user-1', 'low')).toBeUndefined();
  });

  it('should not affect other users', () => {
    service.setChannelOverride('user-1', 'normal', 'sms');
    expect(service.resolveChannel('user-2', 'normal')).toBeUndefined();
  });

  it('should allow overwriting a preference', () => {
    service.setChannelOverride('user-1', 'normal', 'sms');
    service.setChannelOverride('user-1', 'normal', 'webhook');
    expect(service.resolveChannel('user-1', 'normal')).toBe('webhook');
  });

  it('should remove a specific channel override', () => {
    service.setChannelOverride('user-1', 'normal', 'sms');
    service.setChannelOverride('user-1', 'urgent', 'email');
    service.removeChannelOverride('user-1', 'normal');

    expect(service.resolveChannel('user-1', 'normal')).toBeUndefined();
    expect(service.resolveChannel('user-1', 'urgent')).toBe('email');
  });

  it('should return full preferences for a user', () => {
    service.setChannelOverride('user-1', 'normal', 'sms');
    service.setChannelOverride('user-1', 'low', 'email');

    const prefs = service.getPreferences('user-1');
    expect(prefs).toBeDefined();
    expect(prefs?.channelOverrides.normal).toBe('sms');
    expect(prefs?.channelOverrides.low).toBe('email');
  });

  it('should clear preferences for a specific user', () => {
    service.setChannelOverride('user-1', 'normal', 'sms');
    service.setChannelOverride('user-2', 'normal', 'webhook');
    service.clearPreferences('user-1');

    expect(service.getPreferences('user-1')).toBeUndefined();
    expect(service.getPreferences('user-2')).toBeDefined();
  });

  it('should clear all preferences', () => {
    service.setChannelOverride('user-1', 'normal', 'sms');
    service.setChannelOverride('user-2', 'low', 'email');
    service.clearAll();

    expect(service.getPreferences('user-1')).toBeUndefined();
    expect(service.getPreferences('user-2')).toBeUndefined();
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  EmailChannelHandler,
  resetEmailIdCounter,
} from '../../src/services/email-channel.handler.js';
import {
  SmsChannelHandler,
  resetSmsIdCounter,
} from '../../src/services/sms-channel.handler.js';
import {
  WebhookChannelHandler,
  resetWebhookIdCounter,
} from '../../src/services/webhook-channel.handler.js';
import {
  AuditService,
  resetAuditIdCounter,
} from '../../src/services/audit.service.js';
import { NotificationPreferencesService } from '../../src/services/notification-preferences.service.js';
import type { OrderCreatedEvent } from '../../src/events/event-types.js';

describe('Full Notification Flow Integration', () => {
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let emailHandler: EmailChannelHandler;
  let smsHandler: SmsChannelHandler;
  let webhookHandler: WebhookChannelHandler;
  let auditService: AuditService;
  let preferencesService: NotificationPreferencesService;

  beforeEach(() => {
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    emailHandler = new EmailChannelHandler(eventBus);
    smsHandler = new SmsChannelHandler(eventBus);
    webhookHandler = new WebhookChannelHandler(eventBus);
    auditService = new AuditService(eventBus);
    preferencesService = new NotificationPreferencesService();
    notificationService.setPreferencesService(preferencesService);
    resetNotificationIdCounter();
    resetEmailIdCounter();
    resetSmsIdCounter();
    resetWebhookIdCounter();
    resetAuditIdCounter();
  });

  describe('priority routing → channel selection → audit log', () => {
    it('urgent notification routes to SMS and creates audit entry', async () => {
      await notificationService.notify({
        priority: 'urgent',
        recipient: '+1234567890',
        subject: 'Server Down',
        body: 'Production is unreachable',
      });

      // Channel selection: SMS
      expect(smsHandler.getDeliveredMessages()).toHaveLength(1);
      expect(smsHandler.getDeliveredMessages()[0]?.recipient).toBe('+1234567890');
      expect(emailHandler.getDeliveredEmails()).toHaveLength(0);
      expect(webhookHandler.getDeliveredWebhooks()).toHaveLength(0);

      // Audit log
      const entries = auditService.getEntries();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.channel).toBe('sms');
      expect(entries[0]?.recipient).toBe('+1234567890');
      expect(entries[0]?.subject).toBe('Server Down');
    });

    it('normal notification routes to email and creates audit entry', async () => {
      await notificationService.notify({
        priority: 'normal',
        recipient: 'alice@example.com',
        subject: 'Welcome',
        body: 'Welcome aboard',
      });

      expect(emailHandler.getDeliveredEmails()).toHaveLength(1);
      expect(emailHandler.getDeliveredEmails()[0]?.recipient).toBe('alice@example.com');
      expect(smsHandler.getDeliveredMessages()).toHaveLength(0);
      expect(webhookHandler.getDeliveredWebhooks()).toHaveLength(0);

      const entries = auditService.getEntries();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.channel).toBe('email');
    });

    it('low notification routes to webhook and creates audit entry', async () => {
      await notificationService.notify({
        priority: 'low',
        recipient: 'https://hooks.example.com/abc',
        subject: 'Task Done',
        body: 'Background job finished',
      });

      expect(webhookHandler.getDeliveredWebhooks()).toHaveLength(1);
      expect(smsHandler.getDeliveredMessages()).toHaveLength(0);
      expect(emailHandler.getDeliveredEmails()).toHaveLength(0);

      const entries = auditService.getEntries();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.channel).toBe('webhook');
    });

    it('all three priorities produce three audit entries with correct channels', async () => {
      await notificationService.notify({
        priority: 'urgent',
        recipient: '+1234567890',
        subject: 'U',
        body: 'Urgent',
      });
      await notificationService.notify({
        priority: 'normal',
        recipient: 'bob@example.com',
        subject: 'N',
        body: 'Normal',
      });
      await notificationService.notify({
        priority: 'low',
        recipient: 'https://hook.io/x',
        subject: 'L',
        body: 'Low',
      });

      const entries = auditService.getEntries();
      expect(entries).toHaveLength(3);
      expect(entries[0]?.channel).toBe('sms');
      expect(entries[1]?.channel).toBe('email');
      expect(entries[2]?.channel).toBe('webhook');
    });
  });

  describe('user preferences override priority routing', () => {
    it('overrides urgent→sms to urgent→email when user prefers email', async () => {
      preferencesService.setChannelOverride('+1234567890', 'urgent', 'email');

      await notificationService.notify({
        priority: 'urgent',
        recipient: '+1234567890',
        subject: 'Alert',
        body: 'System alert',
      });

      // Routed to email instead of sms
      expect(emailHandler.getDeliveredEmails()).toHaveLength(1);
      expect(smsHandler.getDeliveredMessages()).toHaveLength(0);

      // Audit records the overridden channel
      const entries = auditService.getEntries();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.channel).toBe('email');
    });

    it('overrides normal→email to normal→webhook when user prefers webhook', async () => {
      preferencesService.setChannelOverride('alice@example.com', 'normal', 'webhook');

      await notificationService.notify({
        priority: 'normal',
        recipient: 'alice@example.com',
        subject: 'Update',
        body: 'Status update',
      });

      expect(webhookHandler.getDeliveredWebhooks()).toHaveLength(1);
      expect(emailHandler.getDeliveredEmails()).toHaveLength(0);

      const entries = auditService.getEntries();
      expect(entries[0]?.channel).toBe('webhook');
    });

    it('overrides low→webhook to low→sms when user prefers sms', async () => {
      preferencesService.setChannelOverride('https://hook.io/x', 'low', 'sms');

      await notificationService.notify({
        priority: 'low',
        recipient: 'https://hook.io/x',
        subject: 'Info',
        body: 'Done',
      });

      expect(smsHandler.getDeliveredMessages()).toHaveLength(1);
      expect(webhookHandler.getDeliveredWebhooks()).toHaveLength(0);

      const entries = auditService.getEntries();
      expect(entries[0]?.channel).toBe('sms');
    });

    it('falls back to priority routing when no preference is set', async () => {
      // Set preference for a DIFFERENT user
      preferencesService.setChannelOverride('other-user', 'normal', 'sms');

      await notificationService.notify({
        priority: 'normal',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Fallback test',
      });

      // Default routing: normal → email
      expect(emailHandler.getDeliveredEmails()).toHaveLength(1);
      expect(smsHandler.getDeliveredMessages()).toHaveLength(0);
    });

    it('preference only affects the specified priority', async () => {
      preferencesService.setChannelOverride('alice@example.com', 'normal', 'sms');

      // normal → overridden to sms
      await notificationService.notify({
        priority: 'normal',
        recipient: 'alice@example.com',
        subject: 'N',
        body: 'Normal',
      });

      // urgent → still default sms (no override for urgent)
      await notificationService.notify({
        priority: 'urgent',
        recipient: 'alice@example.com',
        subject: 'U',
        body: 'Urgent',
      });

      expect(smsHandler.getDeliveredMessages()).toHaveLength(2);
      expect(emailHandler.getDeliveredEmails()).toHaveLength(0);
    });
  });

  describe('domain events through the full pipeline', () => {
    it('order:created flows through priority routing, email channel, and audit log', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Notification created with normal priority → email
      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.channel).toBe('email');
      expect(notifications[0]?.priority).toBe('normal');

      // Email delivered
      expect(emailHandler.getDeliveredEmails()).toHaveLength(1);
      expect(emailHandler.getDeliveredEmails()[0]?.recipient).toBe('alice@example.com');

      // Audit entry recorded
      const entries = auditService.getEntries();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.channel).toBe('email');
      expect(entries[0]?.recipient).toBe('alice@example.com');
      expect(entries[0]?.subject).toContain('Order Confirmation');
    });

    it('order:created with user preference overrides default email routing', async () => {
      preferencesService.setChannelOverride('alice@example.com', 'normal', 'sms');

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-2',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Gadget', quantity: 1, unitPrice: 50 },
          ],
          total: 50,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Overridden: normal → sms instead of email
      expect(smsHandler.getDeliveredMessages()).toHaveLength(1);
      expect(emailHandler.getDeliveredEmails()).toHaveLength(0);

      // Audit reflects the overridden channel
      const entries = auditService.getEntries();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.channel).toBe('sms');
    });
  });
});

