+/**
+ * Notification preferences service — allows per-user channel overrides.
+ *
+ * Users can set a preferred channel for a given notification priority. When a
+ * preference exists, it overrides the default priority-based routing. If no
+ * preference is set, the PriorityRouter default is used.
+ *
+ * Example: A user may prefer to receive all 'low' priority notifications via
+ * 'email' instead of the default 'webhook'.
+ */
+
+import type { NotificationPriority } from './priority-router.js';
+
+export type ChannelPreference = 'email' | 'sms' | 'webhook';
+
+export interface UserPreferences {
+  userId: string;
+  channelOverrides: Partial<Record<NotificationPriority, ChannelPreference>>;
+}
+
+export class NotificationPreferencesService {
+  private preferences: Map<string, UserPreferences> = new Map();
+
+  /**
+   * Set a channel override for a user at a given priority level.
+   */
+  setChannelOverride(
+    userId: string,
+    priority: NotificationPriority,
+    channel: ChannelPreference,
+  ): void {
+    let prefs = this.preferences.get(userId);
+    if (!prefs) {
+      prefs = { userId, channelOverrides: {} };
+      this.preferences.set(userId, prefs);
+    }
+    prefs.channelOverrides[priority] = channel;
+  }
+
+  /**
+   * Remove a channel override for a user at a given priority level.
+   */
+  removeChannelOverride(userId: string, priority: NotificationPriority): void {
+    const prefs = this.preferences.get(userId);
+    if (prefs) {
+      delete prefs.channelOverrides[priority];
+    }
+  }
+
+  /**
+   * Resolve the channel for a user and priority. Returns the user's override
+   * if one exists, or undefined to fall back to the default priority routing.
+   */
+  resolveChannel(
+    userId: string,
+    priority: NotificationPriority,
+  ): ChannelPreference | undefined {
+    const prefs = this.preferences.get(userId);
+    if (!prefs) {
+      return undefined;
+    }
+    return prefs.channelOverrides[priority];
+  }
+
+  /**
+   * Get all preferences for a user.
+   */
+  getPreferences(userId: string): UserPreferences | undefined {
+    return this.preferences.get(userId);
+  }
+
+  /**
+   * Remove all preferences for a user.
+   */
+  clearPreferences(userId: string): void {
+    this.preferences.delete(userId);
+  }
+
+  /**
+   * Remove all stored preferences (useful for testing).
+   */
+  clearAll(): void {
+    this.preferences.clear();
+  }
+}

